1	package users
2	
3	import (
4		"net/http"
5		"time"
6	
7		"github.com/labstack/echo/v4"
8	
9		"lms/internal/apperr"
10		"lms/internal/ctxutil"
11		"lms/internal/model"
12	)
13	
14	const (
15		sessionCookieName = "lms_session"
16		sessionCookiePath = "/"
17	)
18	
19	// Handler holds the HTTP handlers for authentication routes.
20	type Handler struct {
21		service *Service
22	}
23	
24	// NewHandler creates a new auth Handler.
25	func NewHandler(service *Service) *Handler {
26		return &Handler{service: service}
27	}
28	
29	// RegisterRoutes registers authentication routes on the given Echo group.
30	// The group is expected to be the /api/v1 group.
31	func (h *Handler) RegisterRoutes(api *echo.Group, authMW ...echo.MiddlewareFunc) {
32		auth := api.Group("/auth")
33		auth.POST("/login", h.Login)
34	
35		// Protected routes require an active session.
36		if len(authMW) > 0 {
37			auth.POST("/logout", h.Logout, authMW...)
38			auth.POST("/stepup", h.StepUp, authMW...)
39		} else {
40			auth.POST("/logout", h.Logout)
41			auth.POST("/stepup", h.StepUp)
42		}
43	}
44	
45	// loginRequest is the JSON body for POST /api/v1/auth/login.
46	type loginRequest struct {
47		Username      string `json:"username"`
48		Password      string `json:"password"`
49		CaptchaKey    string `json:"captcha_key"`
50		CaptchaAnswer string `json:"captcha_answer"`
51	}
52	
53	// loginResponse is the JSON body returned on successful login.
54	type loginResponse struct {
55		User            *model.UserWithRoles `json:"user"`
56		CaptchaRequired bool                 `json:"captcha_required"`
57	}
58	
59	// Login handles POST /api/v1/auth/login.
60	// On success, sets an httpOnly session cookie and returns 200 with the user object.
61	// Sensitive data (password_hash) is never serialised via model tags (json:"-").
62	func (h *Handler) Login(c echo.Context) error {
63		var req loginRequest
64		if err := c.Bind(&req); err != nil {
65			return &apperr.Validation{Field: "body", Message: "invalid JSON"}
66		}
67		if req.Username == "" || req.Password == "" {
68			return &apperr.Validation{Field: "username", Message: "username and password are required"}
69		}
70	
71		workstationID := ctxutil.GetWorkstationID(c)
72		ipAddr := ctxutil.GetIPAddress(c)
73	
74		result, err := h.service.Login(
75			c.Request().Context(),
76			req.Username, req.Password,
77			req.CaptchaKey, req.CaptchaAnswer,
78			workstationID, ipAddr,
79		)
80		if err != nil {
81			return err
82		}
83	
84		// Set the session cookie — httpOnly, SameSite=Strict, no Secure flag
85		// (offline-first deployment with no TLS assumed at this stage).
86		cookie := &http.Cookie{
87			Name:     sessionCookieName,
88			Value:    result.SessionToken,
89			Path:     sessionCookiePath,
90			HttpOnly: true,
91			SameSite: http.SameSiteStrictMode,
92			Secure:   false,
93			MaxAge:   0, // session cookie — expires when browser closes
94			Expires:  result.Session.ExpiresAt,
95		}
96		c.SetCookie(cookie)
97	
98		return c.JSON(http.StatusOK, loginResponse{
99			User:            result.User,
100			CaptchaRequired: false,
101		})
102	}
103	
104	// Logout handles POST /api/v1/auth/logout.
105	// Invalidates the session and clears the cookie. Returns 204 No Content.
106	func (h *Handler) Logout(c echo.Context) error {
107		ctx := c.Request().Context()
108		session, ok := ctxutil.GetSession(ctx)
109		if !ok || session == nil {
110			return &apperr.Unauthorized{}
111		}
112		user, _ := ctxutil.GetUser(ctx)
113	
114		var userID, username string
115		if user != nil && user.User != nil {
116			userID = user.User.ID
117			username = user.User.Username
118		}
119	
120		workstationID := ctxutil.GetWorkstationID(c)
121		if err := h.service.Logout(ctx, session.ID, userID, username, workstationID); err != nil {
122			return err
123		}
124	
125		// Clear the session cookie by expiring it immediately.
126		c.SetCookie(&http.Cookie{
127			Name:     sessionCookieName,
128			Value:    "",
129			Path:     sessionCookiePath,
130			HttpOnly: true,
131			SameSite: http.SameSiteStrictMode,
132			Secure:   false,
133			MaxAge:   -1,
134			Expires:  time.Unix(0, 0),
135		})
136	
137		return c.NoContent(http.StatusNoContent)
138	}
139	
140	// stepUpRequest is the JSON body for POST /api/v1/auth/stepup.
141	type stepUpRequest struct {
142		Password string `json:"password"`
143	}
144	
145	// StepUp handles POST /api/v1/auth/stepup.
146	// Verifies the user's current password without creating a new session.
147	// Returns 200 {ok: true} on success, 401 on failure.
148	func (h *Handler) StepUp(c echo.Context) error {
149		var req stepUpRequest
150		if err := c.Bind(&req); err != nil {
151			return &apperr.Validation{Field: "body", Message: "invalid JSON"}
152		}
153		if req.Password == "" {
154			return &apperr.Validation{Field: "password", Message: "password is required"}
155		}
156	
157		user, ok := ctxutil.GetUser(c.Request().Context())
158		if !ok || user == nil {
159			return &apperr.Unauthorized{}
160		}
161	
162		if err := h.service.StepUp(c.Request().Context(), user.User.ID, req.Password); err != nil {
163			return err
164		}
165	
166		return c.JSON(http.StatusOK, map[string]bool{"ok": true})
167	}
