1	package users
2	
3	import (
4		"context"
5		"crypto/rand"
6		"crypto/sha256"
7		"encoding/hex"
8		"fmt"
9		"math/big"
10		"strings"
11		"time"
12	
13		"golang.org/x/crypto/bcrypt"
14	
15		"lms/internal/apperr"
16		auditpkg "lms/internal/audit"
17		"lms/internal/model"
18	)
19	
20	// Lockout and CAPTCHA thresholds.
21	const (
22		// CaptchaThreshold is the number of failed attempts before CAPTCHA is required.
23		CaptchaThreshold = 3
24		// LockoutThreshold is the number of failed attempts before the account is locked.
25		LockoutThreshold = 5
26		// LockoutDuration is how long an account is locked after reaching LockoutThreshold.
27		LockoutDuration = 15 * time.Minute
28		// CaptchaTTL is how long a CAPTCHA challenge remains valid.
29		CaptchaTTL = 10 * time.Minute
30	)
31	
32	// LoginResult is returned on successful authentication.
33	type LoginResult struct {
34		SessionToken string          // raw token — must be set as cookie, never logged
35		Session      *model.Session
36		User         *model.UserWithRoles
37	}
38	
39	// Service provides authentication operations for staff users.
40	type Service struct {
41		userRepo    Repository
42		sessionRepo SessionRepository
43		captchaRepo CaptchaRepository
44		auditLogger *auditpkg.Logger
45		inactivitySeconds int
46	}
47	
48	// NewService creates a new auth Service with all required dependencies.
49	func NewService(
50		userRepo Repository,
51		sessionRepo SessionRepository,
52		captchaRepo CaptchaRepository,
53		auditLogger *auditpkg.Logger,
54		inactivitySeconds int,
55	) *Service {
56		return &Service{
57			userRepo:          userRepo,
58			sessionRepo:       sessionRepo,
59			captchaRepo:       captchaRepo,
60			auditLogger:       auditLogger,
61			inactivitySeconds: inactivitySeconds,
62		}
63	}
64	
65	// Login authenticates a user and creates a new session.
66	// It enforces lockout, CAPTCHA, and failed-attempt tracking.
67	// Generic error messages are used throughout to prevent user enumeration.
68	func (s *Service) Login(
69		ctx context.Context,
70		username, password, captchaKey, captchaAnswer,
71		workstationID, ipAddr string,
72	) (*LoginResult, error) {
73		// 1. Look up the user. On not-found, return generic error to prevent enumeration.
74		u, err := s.userRepo.GetByUsername(ctx, username)
75		if err != nil {
76			// Do not reveal that the username does not exist.
77			s.auditLogger.LogLoginFailed(ctx, username, workstationID, ipAddr, "user_not_found")
78			return nil, &apperr.Validation{Message: "invalid credentials"}
79		}
80	
81		// 2. If account is inactive, return generic error.
82		if !u.IsActive {
83			s.auditLogger.LogLoginFailed(ctx, username, workstationID, ipAddr, "account_inactive")
84			return nil, &apperr.Validation{Message: "invalid credentials"}
85		}
86	
87		// 3. If account is locked, return AccountLocked with remaining seconds.
88		now := time.Now()
89		if u.IsLocked(now) {
90			remaining := int(u.LockedUntil.Sub(now).Seconds())
91			if remaining < 0 {
92				remaining = 0
93			}
94			return nil, &apperr.AccountLocked{SecondsRemaining: remaining}
95		}
96	
97		// 4. Check if CAPTCHA is required (>= 3 failed attempts and no captchaKey provided).
98		if u.FailedAttempts >= CaptchaThreshold && captchaKey == "" {
99			challenge, err := s.issueCaptcha(ctx, username, ipAddr)
100			if err != nil {
101				return nil, &apperr.Internal{Cause: err}
102			}
103			return nil, &apperr.CaptchaRequired{ChallengeKey: challenge.ChallengeKey}
104		}
105	
106		// 5. If captchaKey is provided, validate it before checking the password.
107		if captchaKey != "" {
108			if err := s.validateCaptcha(ctx, captchaKey, captchaAnswer); err != nil {
109				// Wrong CAPTCHA answer: increment failed attempts but don't return a
110				// new CAPTCHA — let the caller retry from the beginning.
111				newCount, _ := s.userRepo.IncrementFailedAttempts(ctx, u.ID)
112				s.auditLogger.LogLoginFailed(ctx, username, workstationID, ipAddr, "captcha_wrong")
113				if newCount >= LockoutThreshold {
114					lockUntil := time.Now().Add(LockoutDuration)
115					_ = s.userRepo.SetLockedUntil(ctx, u.ID, lockUntil)
116					s.auditLogger.LogLockout(ctx, u.ID, u.Username)
117					return nil, &apperr.AccountLocked{SecondsRemaining: int(LockoutDuration.Seconds())}
118				}
119				return nil, &apperr.Validation{Message: "invalid captcha answer"}
120			}
121		}
122	
123		// 6. Verify bcrypt password.
124		if err := bcrypt.CompareHashAndPassword([]byte(u.PasswordHash), []byte(password)); err != nil {
125			// Wrong password — increment failed attempts.
126			newCount, incErr := s.userRepo.IncrementFailedAttempts(ctx, u.ID)
127			if incErr != nil {
128				newCount = u.FailedAttempts + 1
129			}
130	
131			s.auditLogger.LogLoginFailed(ctx, username, workstationID, ipAddr, "wrong_password")
132	
133			if newCount >= LockoutThreshold {
134				lockUntil := time.Now().Add(LockoutDuration)
135				_ = s.userRepo.SetLockedUntil(ctx, u.ID, lockUntil)
136				s.auditLogger.LogLockout(ctx, u.ID, u.Username)
137				return nil, &apperr.AccountLocked{SecondsRemaining: int(LockoutDuration.Seconds())}
138			}
139	
140			if newCount >= CaptchaThreshold {
141				// Issue a CAPTCHA challenge for the next attempt.
142				challenge, cErr := s.issueCaptcha(ctx, username, ipAddr)
143				if cErr != nil {
144					return nil, &apperr.Validation{Message: "invalid credentials"}
145				}
146				return nil, &apperr.CaptchaRequired{ChallengeKey: challenge.ChallengeKey}
147			}
148	
149			return nil, &apperr.Validation{Message: "invalid credentials"}
150		}
151	
152		// 7. Password correct — reset failed attempts and update last_login.
153		_ = s.userRepo.ResetFailedAttempts(ctx, u.ID)
154		_ = s.userRepo.SetLastLogin(ctx, u.ID)
155	
156		// 8. Load roles and permissions.
157		roles, err := s.userRepo.GetRoles(ctx, u.ID)
158		if err != nil {
159			return nil, &apperr.Internal{Cause: err}
160		}
161		roleNames := make([]string, len(roles))
162		for i, r := range roles {
163			roleNames[i] = r.Name
164		}
165		perms, err := s.userRepo.GetPermissions(ctx, u.ID)
166		if err != nil {
167			return nil, &apperr.Internal{Cause: err}
168		}
169	
170		// 9. Generate a 32-byte cryptographically random session token.
171		rawToken, err := generateToken()
172		if err != nil {
173			return nil, &apperr.Internal{Cause: err}
174		}
175	
176		// 10. Hash the token for storage. Only the hash is persisted.
177		hash := sha256.Sum256([]byte(rawToken))
178		tokenHash := hex.EncodeToString(hash[:])
179	
180		// 11. Create the session record.
181		session := &model.Session{
182			TokenHash:     tokenHash,
183			UserID:        u.ID,
184			WorkstationID: strPtrOrNil(workstationID),
185			IPAddress:     strPtrOrNil(ipAddr),
186			ExpiresAt:     time.Now().Add(time.Duration(s.inactivitySeconds) * time.Second),
187			IsValid:       true,
188		}
189		if err := s.sessionRepo.Create(ctx, session); err != nil {
190			return nil, &apperr.Internal{Cause: err}
191		}
192	
193		// 12. Log the successful login.
194		s.auditLogger.LogLogin(ctx, u.ID, u.Username, workstationID, ipAddr)
195	
196		userWithRoles := &model.UserWithRoles{
197			User:        u,
198			Roles:       roleNames,
199			Permissions: perms,
200		}
201	
202		return &LoginResult{
203			SessionToken: rawToken,
204			Session:      session,
205			User:         userWithRoles,
206		}, nil
207	}
208	
209	// Logout invalidates the given session and logs the event.
210	func (s *Service) Logout(ctx context.Context, sessionID, userID, username, workstationID string) error {
211		if err := s.sessionRepo.Invalidate(ctx, sessionID); err != nil {
212			return &apperr.Internal{Cause: err}
213		}
214		s.auditLogger.LogLogout(ctx, userID, username, sessionID)
215		return nil
216	}
217	
218	// StepUp verifies the user's current password as a secondary authentication check.
219	// It does not create a new session. Returns nil on success.
220	func (s *Service) StepUp(ctx context.Context, userID, password string) error {
221		u, err := s.userRepo.GetByID(ctx, userID)
222		if err != nil {
223			return &apperr.Unauthorized{}
224		}
225		if err := bcrypt.CompareHashAndPassword([]byte(u.PasswordHash), []byte(password)); err != nil {
226			return &apperr.Unauthorized{}
227		}
228		return nil
229	}
230	
231	// issueCaptcha generates and stores a new math CAPTCHA challenge.
232	// The challenge text is "What is X + Y?" where X, Y are 1-9 integers.
233	func (s *Service) issueCaptcha(ctx context.Context, username, ipAddr string) (*model.CaptchaChallenge, error) {
234		x, err := randInt(1, 9)
235		if err != nil {
236			return nil, fmt.Errorf("issueCaptcha: generate X: %w", err)
237		}
238		y, err := randInt(1, 9)
239		if err != nil {
240			return nil, fmt.Errorf("issueCaptcha: generate Y: %w", err)
241		}
242		answer := fmt.Sprintf("%d", x+y)
243	
244		// Store only the hash of the answer.
245		answerHash := hashAnswer(answer)
246	
247		// Generate an opaque challenge key (32 random bytes, hex-encoded).
248		keyBytes := make([]byte, 16)
249		if _, err := rand.Read(keyBytes); err != nil {
250			return nil, fmt.Errorf("issueCaptcha: generate key: %w", err)
251		}
252		challengeKey := hex.EncodeToString(keyBytes)
253	
254		challenge := &model.CaptchaChallenge{
255			ChallengeKey: challengeKey,
256			AnswerHash:   answerHash,
257			Username:     strPtrOrNil(username),
258			IPAddress:    strPtrOrNil(ipAddr),
259			ExpiresAt:    time.Now().Add(CaptchaTTL),
260		}
261	
262		// Store the challenge text as metadata in the ChallengeKey so the handler
263		// can return it. We embed the question text in the challenge key using a
264		// separator; the repo only stores challenge_key verbatim.
265		// We keep the challenge text out of the DB and return it from here.
266		// The handler will return both the key and the display text.
267	
268		// Store separately — we embed the question in a way the handler can retrieve it.
269		// Since CaptchaChallenge.ChallengeKey is the opaque client token, we'll pass
270		// the question text via a separate mechanism (returned from issueCaptcha and
271		// embedded in the error — see CaptchaRequired extension in the handler).
272	
273		// For simplicity and DB compatibility: encode question into the ChallengeKey
274		// as "<key>:<question>" — the client only uses the key part, and the handler
275		// extracts the question from the full string before splitting on ':'.
276		// This avoids changing the DB schema.
277		displayQuestion := fmt.Sprintf("What is %d + %d?", x, y)
278		challenge.ChallengeKey = challengeKey + ":" + displayQuestion
279	
280		if err := s.captchaRepo.Create(ctx, challenge); err != nil {
281			return nil, fmt.Errorf("issueCaptcha: store: %w", err)
282		}
283	
284		return challenge, nil
285	}
286	
287	// validateCaptcha checks a CAPTCHA answer. Marks the challenge used even on failure.
288	func (s *Service) validateCaptcha(ctx context.Context, captchaKey, answer string) error {
289		// Extract the opaque key portion (before the ':' separator if present).
290		key := extractKey(captchaKey)
291	
292		challenge, err := s.captchaRepo.GetByKey(ctx, captchaKey)
293		if err != nil {
294			// Try with just the key portion (client may have stripped the question text).
295			challenge, err = s.captchaRepo.GetByKey(ctx, key)
296			if err != nil {
297				return fmt.Errorf("captcha not found or expired")
298			}
299		}
300	
301		// Always mark used to prevent replay.
302		_ = s.captchaRepo.MarkUsed(ctx, challenge.ID)
303	
304		// Compare the hash of the submitted answer (case-insensitive).
305		submittedHash := hashAnswer(strings.TrimSpace(strings.ToLower(answer)))
306		if submittedHash != challenge.AnswerHash {
307			return fmt.Errorf("wrong captcha answer")
308		}
309		return nil
310	}
311	
312	// hashAnswer returns the hex-encoded SHA-256 hash of the normalized answer.
313	func hashAnswer(answer string) string {
314		normalised := strings.TrimSpace(strings.ToLower(answer))
315		hash := sha256.Sum256([]byte(normalised))
316		return hex.EncodeToString(hash[:])
317	}
318	
319	// generateToken generates a 32-byte cryptographically random token,
320	// returned as a 64-character hex string.
321	func generateToken() (string, error) {
322		b := make([]byte, 32)
323		if _, err := rand.Read(b); err != nil {
324			return "", fmt.Errorf("generateToken: %w", err)
325		}
326		return hex.EncodeToString(b), nil
327	}
328	
329	// randInt returns a random integer in [min, max] using crypto/rand.
330	func randInt(min, max int) (int, error) {
331		n, err := rand.Int(rand.Reader, big.NewInt(int64(max-min+1)))
332		if err != nil {
333			return 0, err
334		}
335		return int(n.Int64()) + min, nil
336	}
337	
338	// strPtrOrNil returns a pointer to s if non-empty, otherwise nil.
339	func strPtrOrNil(s string) *string {
340		if s == "" {
341			return nil
342		}
343		return &s
344	}
345	
346	// extractKey returns the portion of a challenge key before the first ':'.
347	// If no ':' is present, returns the full key.
348	func extractKey(key string) string {
349		if idx := strings.Index(key, ":"); idx >= 0 {
350			return key[:idx]
351		}
352		return key
353	}
