1	package middleware
2	
3	import (
4		"crypto/sha256"
5		"encoding/hex"
6		"net/http"
7		"time"
8	
9		"github.com/labstack/echo/v4"
10	
11		"lms/internal/apperr"
12		"lms/internal/ctxutil"
13		"lms/internal/domain/users"
14		"lms/internal/model"
15	)
16	
17	const sessionCookieName = "lms_session"
18	
19	// RequireAuth is an Echo middleware that validates the session cookie and
20	// loads the authenticated user into the request context.
21	//
22	// On every request:
23	//  1. Reads the "lms_session" cookie.
24	//  2. SHA-256 hashes the raw cookie value → hex string → looks up in session repo.
25	//  3. If no valid session found, returns 401.
26	//  4. Extends the session expiry (touches last_active_at).
27	//  5. Loads the user + roles + permissions and stores in context.
28	//  6. Sets branch scope in context.
29	func RequireAuth(sessionRepo users.SessionRepository, userRepo users.Repository, inactivitySecs int) echo.MiddlewareFunc {
30		return func(next echo.HandlerFunc) echo.HandlerFunc {
31			return func(c echo.Context) error {
32				session, user, err := loadSession(c, sessionRepo, userRepo, inactivitySecs)
33				if err != nil {
34					return c.JSON(http.StatusUnauthorized, map[string]string{
35						"error":  "unauthenticated",
36						"detail": "no valid session",
37					})
38				}
39	
40				// Store user and session in context.
41				ctx := c.Request().Context()
42				ctx = ctxutil.SetUser(ctx, user)
43				ctx = ctxutil.SetSession(ctx, session)
44	
45				// Set branch scope.
46				branchID := resolveBranchID(user)
47				ctx = ctxutil.SetBranchID(ctx, branchID)
48	
49				c.SetRequest(c.Request().WithContext(ctx))
50				return next(c)
51			}
52		}
53	}
54	
55	// OptionalAuth is like RequireAuth but does not return 401 on a missing or
56	// invalid session. Use for routes that work for both authenticated and
57	// unauthenticated callers.
58	func OptionalAuth(sessionRepo users.SessionRepository, userRepo users.Repository, inactivitySecs int) echo.MiddlewareFunc {
59		return func(next echo.HandlerFunc) echo.HandlerFunc {
60			return func(c echo.Context) error {
61				session, user, err := loadSession(c, sessionRepo, userRepo, inactivitySecs)
62				if err == nil && session != nil && user != nil {
63					ctx := c.Request().Context()
64					ctx = ctxutil.SetUser(ctx, user)
65					ctx = ctxutil.SetSession(ctx, session)
66					branchID := resolveBranchID(user)
67					ctx = ctxutil.SetBranchID(ctx, branchID)
68					c.SetRequest(c.Request().WithContext(ctx))
69				}
70				return next(c)
71			}
72		}
73	}
74	
75	// loadSession extracts and validates the session from the request cookie.
76	// Returns the session, user-with-roles, and any error encountered.
77	func loadSession(
78		c echo.Context,
79		sessionRepo users.SessionRepository,
80		userRepo users.Repository,
81		inactivitySecs int,
82	) (*model.Session, *model.UserWithRoles, error) {
83		cookie, err := c.Cookie(sessionCookieName)
84		if err != nil || cookie.Value == "" {
85			return nil, nil, &apperr.Unauthorized{}
86		}
87	
88		// Hash the raw cookie value for lookup. Never store or log the raw token.
89		hash := sha256.Sum256([]byte(cookie.Value))
90		tokenHash := hex.EncodeToString(hash[:])
91	
92		ctx := c.Request().Context()
93		session, err := sessionRepo.GetByTokenHash(ctx, tokenHash)
94		if err != nil {
95			return nil, nil, &apperr.Unauthorized{}
96		}
97	
98		// Verify expiry — the repo query already checks this, but belt-and-suspenders.
99		if session.ExpiresAt.Before(time.Now()) {
100			_ = sessionRepo.Invalidate(ctx, session.ID)
101			return nil, nil, &apperr.Unauthorized{}
102		}
103	
104		// Touch the session — extend expiry by the inactivity window.
105		newExpiry := time.Now().Add(time.Duration(inactivitySecs) * time.Second)
106		if err := sessionRepo.Touch(ctx, session.ID, newExpiry); err != nil {
107			// Non-fatal: log would be appropriate here in production, but don't block.
108			_ = err
109		}
110		session.ExpiresAt = newExpiry
111	
112		// Load the user with roles and permissions.
113		u, err := userRepo.GetByID(ctx, session.UserID)
114		if err != nil {
115			return nil, nil, &apperr.Unauthorized{}
116		}
117		if !u.IsActive {
118			return nil, nil, &apperr.Unauthorized{}
119		}
120	
121		roles, err := userRepo.GetRoles(ctx, u.ID)
122		if err != nil {
123			return nil, nil, &apperr.Unauthorized{}
124		}
125		roleNames := make([]string, len(roles))
126		for i, r := range roles {
127			roleNames[i] = r.Name
128		}
129	
130		perms, err := userRepo.GetPermissions(ctx, u.ID)
131		if err != nil {
132			return nil, nil, &apperr.Unauthorized{}
133		}
134	
135		userWithRoles := &model.UserWithRoles{
136			User:        u,
137			Roles:       roleNames,
138			Permissions: perms,
139		}
140	
141		return session, userWithRoles, nil
142	}
