11	// RequirePermission returns an Echo middleware that checks whether the
12	// authenticated user holds the named permission. Must be used AFTER RequireAuth.
13	// Returns 403 if the user lacks the permission.
14	func RequirePermission(perm string) echo.MiddlewareFunc {
15		return func(next echo.HandlerFunc) echo.HandlerFunc {
16			return func(c echo.Context) error {
17				user, ok := ctxutil.GetUser(c.Request().Context())
18				if !ok || user == nil {
19					return c.JSON(http.StatusUnauthorized, map[string]string{
20						"error": "unauthenticated",
21					})
22				}
23				if !user.HasPermission(perm) {
24					return c.JSON(http.StatusForbidden, map[string]string{
25						"error": "forbidden",
26					})
27				}
28				return next(c)
29			}
30		}
31	}
32	
33	// RequireRole returns an Echo middleware that checks whether the authenticated
34	// user holds the named role. Must be used AFTER RequireAuth.
35	// Returns 403 if the user lacks the role.
36	func RequireRole(role string) echo.MiddlewareFunc {
37		return func(next echo.HandlerFunc) echo.HandlerFunc {
38			return func(c echo.Context) error {
39				user, ok := ctxutil.GetUser(c.Request().Context())
40				if !ok || user == nil {
41					return c.JSON(http.StatusUnauthorized, map[string]string{
42						"error": "unauthenticated",
43					})
44				}
45				for _, r := range user.Roles {
46					if r == role {
47						return next(c)
48					}
49				}
50				return c.JSON(http.StatusForbidden, map[string]string{
51					"error": "forbidden",
52				})
53			}
54		}
55	}
