// Session state is verified against the server on initial load (GET /auth/me).
// Any 401 response clears local auth state and triggers a redirect to login.

import React, { createContext, useCallback, useContext, useEffect, useState } from 'react';
import { apiClient, HttpError } from '../api/client';

// ── Types ─────────────────────────────────────────────────────────────────────

export interface AuthUserCore {
  id: string;
  username: string;
  email: string;
  is_active: boolean;
  failed_attempts: number;
  locked_until?: string;
  last_login_at?: string;
  created_at: string;
  updated_at: string;
}

// AuthUser matches the server's UserWithRoles JSON shape after json tags were added.
export interface AuthUser {
  user: AuthUserCore;
  roles: string[];
  permissions: string[];
}

export interface LoginRequest {
  username: string;
  password: string;
  captcha_key?: string;
  captcha_answer?: string;
}

// CaptchaChallenge is returned when the server requires CAPTCHA before next login.
export interface CaptchaChallenge {
  key: string;
  question: string;
}

// AccountLocked is returned after 5 failed login attempts.
export interface AccountLocked {
  seconds_remaining: number;
}

type AuthStatus = 'loading' | 'unauthenticated' | 'authenticated';

export interface AuthState {
  status: AuthStatus;
  user: AuthUser | null;
}

interface AuthContextValue {
  auth: AuthState;
  login: (req: LoginRequest) => Promise<void>;
  logout: () => Promise<void>;
  hasPermission: (perm: string) => boolean;
  hasRole: (role: string) => boolean;
  getPrimaryRole: () => string;
}

// ── Context ───────────────────────────────────────────────────────────────────

const AuthContext = createContext<AuthContextValue | null>(null);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [auth, setAuth] = useState<AuthState>({ status: 'loading', user: null });

  // On mount: verify session by calling GET /auth/me.
  // The server validates the httpOnly session cookie and returns the current user.
  // This is the authoritative session check — no client-side token storage needed.
  useEffect(() => {
    apiClient
      .get<AuthUser>('/auth/me')
      .then((user) => setAuth({ status: 'authenticated', user }))
      .catch(() => setAuth({ status: 'unauthenticated', user: null }));
  }, []);

  const login = useCallback(async (req: LoginRequest) => {
    // POST /auth/login returns { user: AuthUser, captcha_required: bool } on success.
    // The server sets the session cookie automatically.
    const res = await apiClient.post<{ user: AuthUser; captcha_required: boolean }>(
      '/auth/login',
      req,
    );
    setAuth({ status: 'authenticated', user: res.user });
  }, []);

  const logout = useCallback(async () => {
    try {
      // POST /auth/logout invalidates the server session.
      await apiClient.post<void>('/auth/logout');
    } catch {
      // Clear local state regardless of server response.
    }
    setAuth({ status: 'unauthenticated', user: null });
  }, []);

  const hasPermission = useCallback(
    (perm: string) => auth.user?.permissions.includes(perm) ?? false,
    [auth.user],
  );

  const hasRole = useCallback(
    (role: string) => auth.user?.roles.includes(role) ?? false,
    [auth.user],
  );

  const getPrimaryRole = useCallback((): string => {
    if (!auth.user) return 'unknown';
    const { roles } = auth.user;
    if (roles.includes('administrator')) return 'administrator';
    if (roles.includes('content_moderator')) return 'content_moderator';
    if (roles.includes('operations_staff')) return 'operations_staff';
    return roles[0] ?? 'unknown';
  }, [auth.user]);

  return (
    <AuthContext.Provider value={{ auth, login, logout, hasPermission, hasRole, getPrimaryRole }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth(): AuthContextValue {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used inside AuthProvider');
  return ctx;
}
"}

