// Navigation items are filtered by role — users only see what they can access.
// Uses React Router's Outlet to render the active route's page in the content area.

import { NavLink, Outlet, useNavigate } from 'react-router-dom';
import { useAuth } from '../auth/AuthContext';

// ── Styles ────────────────────────────────────────────────────────────────────

const S = {
  shell: {
    display: 'flex',
    height: '100vh',
    overflow: 'hidden',
    fontFamily: 'system-ui, -apple-system, sans-serif',
    fontSize: '0.875rem',
    color: '#1a1a2e',
    background: '#f3f4f6',
  } as React.CSSProperties,

  sidebar: {
    width: '220px',
    flexShrink: 0,
    background: '#1e2235',
    color: '#c8d0e0',
    display: 'flex',
    flexDirection: 'column' as const,
    overflow: 'hidden',
  } as React.CSSProperties,

  sidebarHeader: {
    padding: '1rem 1rem 0.75rem',
    borderBottom: '1px solid #2a3050',
  } as React.CSSProperties,

  sidebarTitle: {
    fontSize: '0.8125rem',
    fontWeight: 700,
    color: '#e2e8f0',
    letterSpacing: '0.02em',
    lineHeight: 1.3,
  } as React.CSSProperties,

  sidebarNav: {
    flex: 1,
    overflowY: 'auto' as const,
    padding: '0.5rem 0',
  } as React.CSSProperties,

  navSection: {
    padding: '0.5rem 1rem 0.25rem',
    fontSize: '0.6875rem',
    fontWeight: 600,
    textTransform: 'uppercase' as const,
    letterSpacing: '0.08em',
    color: '#6b7a99',
  } as React.CSSProperties,

  sidebarFooter: {
    borderTop: '1px solid #2a3050',
    padding: '0.75rem 1rem',
  } as React.CSSProperties,

  userInfo: {
    fontSize: '0.75rem',
    color: '#94a3b8',
    marginBottom: '0.5rem',
  } as React.CSSProperties,

  logoutBtn: {
    background: 'none',
    border: '1px solid #2a3050',
    color: '#94a3b8',
    padding: '0.375rem 0.75rem',
    borderRadius: '4px',
    cursor: 'pointer',
    fontSize: '0.75rem',
    width: '100%',
    textAlign: 'left' as const,
  } as React.CSSProperties,

  main: {
    flex: 1,
    display: 'flex',
    flexDirection: 'column' as const,
    overflow: 'hidden',
  } as React.CSSProperties,

  topBar: {
    background: '#ffffff',
    borderBottom: '1px solid #e5e7eb',
    padding: '0.625rem 1.5rem',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between',
    flexShrink: 0,
  } as React.CSSProperties,

  content: {
    flex: 1,
    overflowY: 'auto' as const,
    padding: '1.5rem',
  } as React.CSSProperties,
};

// ── Navigation item definitions ───────────────────────────────────────────────

interface NavItem {
  to: string;
  label: string;
  section?: string; // section header above this item
  roles: string[];  // which roles see this item
}

const NAV_ITEMS: NavItem[] = [
  // All roles
  { to: '/dashboard', label: 'Dashboard', section: undefined, roles: ['administrator', 'operations_staff', 'content_moderator'] },

  // Operations
  { to: '/readers',     label: 'Readers',         section: 'Operations', roles: ['administrator', 'operations_staff', 'content_moderator'] },
  { to: '/holdings',    label: 'Holdings & Copies',                       roles: ['administrator', 'operations_staff'] },
  { to: '/circulation', label: 'Circulation',                             roles: ['administrator', 'operations_staff'] },
  { to: '/stocktake',   label: 'Stocktake',                               roles: ['administrator', 'operations_staff'] },

  // Programs
  { to: '/programs',    label: 'Programs',   section: 'Programs', roles: ['administrator', 'operations_staff'] },
  { to: '/enrollments', label: 'Enrollments',                     roles: ['administrator', 'operations_staff'] },

  // Content
  { to: '/moderation', label: 'Moderation Queue', section: 'Content', roles: ['administrator', 'content_moderator'] },
  { to: '/content',    label: 'Content',                                roles: ['administrator', 'content_moderator'] },
  { to: '/feedback',   label: 'Feedback',                               roles: ['administrator', 'operations_staff', 'content_moderator'] },
  { to: '/appeals',    label: 'Appeals',                                roles: ['administrator', 'operations_staff', 'content_moderator'] },

  // System
  { to: '/reports',  label: 'Reports',         section: 'System', roles: ['administrator', 'operations_staff', 'content_moderator'] },
  { to: '/imports',  label: 'Imports/Exports',                    roles: ['administrator', 'operations_staff'] },
  { to: '/users',    label: 'Users',                              roles: ['administrator'] },
];

const ROLE_LABELS: Record<string, string> = {
  administrator: 'Administrator',
  operations_staff: 'Operations Staff',
  content_moderator: 'Content Moderator',
};

// ── NavLink styled component ──────────────────────────────────────────────────

function SideNavLink({ to, label }: { to: string; label: string }) {
  return (
    <NavLink
      to={to}
      style={({ isActive }) => ({
        display: 'block',
        padding: '0.375rem 1rem',
        color: isActive ? '#e2e8f0' : '#94a3b8',
        background: isActive ? '#2a3a6e' : 'transparent',
        textDecoration: 'none',
        borderLeft: isActive ? '3px solid #4a7fe0' : '3px solid transparent',
        fontSize: '0.8125rem',
        transition: 'background 0.1s',
      })}
    >
      {label}
    </NavLink>
  );
}

// ── AppShell ──────────────────────────────────────────────────────────────────

export default function AppShell() {
  const { auth, logout, getPrimaryRole } = useAuth();
  const navigate = useNavigate();

  const primaryRole = getPrimaryRole();
  const username = auth.user?.user.username ?? '';
  const roleLabel = ROLE_LABELS[primaryRole] ?? primaryRole;

  // Filter nav items to those the user's role allows.
  const visibleItems = NAV_ITEMS.filter((item) =>
    auth.user?.roles.some((r) => item.roles.includes(r)),
  );

  async function handleLogout() {
    await logout();
    navigate('/login', { replace: true });
  }

  // Track last rendered section to emit section headers only once.
  let lastSection: string | undefined = undefined;

  return (
    <div style={S.shell}>
      {/* ── Sidebar ── */}
      <aside style={S.sidebar}>
        <div style={S.sidebarHeader}>
          <div style={S.sidebarTitle}>Library Operations<br />& Enrollment Suite</div>
        </div>

        <nav style={S.sidebarNav} aria-label="Main navigation">
          {visibleItems.map((item) => {
            const showSection = item.section && item.section !== lastSection;
            if (showSection) lastSection = item.section;
            return (
              <div key={item.to}>
                {showSection && (
                  <div style={S.navSection}>{item.section}</div>
                )}
                <SideNavLink to={item.to} label={item.label} />
              </div>
            );
          })}
        </nav>

        <div style={S.sidebarFooter}>
          <div style={S.userInfo}>
            <strong style={{ color: '#c8d0e0' }}>{username}</strong>
            <br />
            {roleLabel}
          </div>
          <button style={S.logoutBtn} onClick={handleLogout} type="button">
            Sign out
          </button>
        </div>
      </aside>

      {/* ── Main ── */}
      <div style={S.main}>
        <header style={S.topBar}>
          <span style={{ fontWeight: 600, fontSize: '0.875rem' }}>
            Library Management System
          </span>
          <span style={{ fontSize: '0.75rem', color: '#6b7280' }}>
            Signed in as <strong>{username}</strong> · {roleLabel}
          </span>
        </header>

        <main style={S.content}>
          <Outlet />
        </main>
      </div>
    </div>
  );
}
"}

