    color: '#dc2626',
  } as React.CSSProperties,

  warnBox: {
    background: '#fef3c7',
    border: '1px solid #f59e0b',
    borderRadius: '4px',
    padding: '0.75rem 1rem',
    marginBottom: '1rem',
    fontSize: '0.8125rem',
    color: '#92400e',
  } as React.CSSProperties,

  captchaBox: {
    background: '#eff6ff',
    border: '1px solid #bfdbfe',
    borderRadius: '4px',
    padding: '0.75rem 1rem',
    marginBottom: '1rem',
    fontSize: '0.8125rem',
    color: '#1e40af',
  } as React.CSSProperties,
};

