          <input
            id="username"
            type="text"
            autoComplete="username"
            autoFocus
            required
            style={S.input}
            value={username}
            onChange={(e) => setUsername(e.target.value)}
            disabled={submitting}
          />

          <label style={S.label} htmlFor="password">Password</label>
          <input
            id="password"
            type="password"
            autoComplete="current-password"
            required
            style={S.input}
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            disabled={submitting}
          />

          {/* CAPTCHA section — shown after 3 failed login attempts */}
          {captcha && (
            <>
              <div style={S.captchaBox} role="status">
                <strong>Security check required</strong>
                <br />
                {captcha.question}
              </div>
              {error?.kind === 'captcha_required' && (
                <div style={S.errorBox} role="alert">
                  Incorrect answer. Please try again.
                </div>
              )}
              <label style={S.label} htmlFor="captcha_answer">Answer</label>
              <input
                id="captcha_answer"
                type="text"
                inputMode="numeric"
                required
                style={S.input}
                value={captchaAnswer}
                onChange={(e) => setCaptchaAnswer(e.target.value)}
                disabled={submitting}
                placeholder="Enter the number"
              />
            </>
          )}

          <button
            type="submit"
            style={{
              ...S.submitBtn,
              opacity: submitting ? 0.7 : 1,
              cursor: submitting ? 'not-allowed' : 'pointer',
            }}
            disabled={submitting}
          >
            {submitting ? 'Signing in…' : 'Sign in'}
          </button>
        </form>
      </div>
    </div>
  );
}
"}

