//   - AuthProvider (session state, login/logout operations)
//   - BrowserRouter (client-side routing)
//   - Route table (protected routes filtered by role)
//
// Phase 5 delivers: login, session UX, and role-based navigation shell.
// Domain feature pages (readers, holdings, etc.) are placeholder screens
// until their respective backend endpoints are implemented.

import { BrowserRouter, Navigate, Route, Routes } from 'react-router-dom';
import { AuthProvider } from './auth/AuthContext';
import AppShell from './components/AppShell';
import ProtectedRoute from './components/ProtectedRoute';
import LoginPage from './pages/LoginPage';
import DashboardPage from './pages/DashboardPage';
import UnauthorizedPage from './pages/UnauthorizedPage';
import NotFoundPage from './pages/NotFoundPage';
import PlaceholderPage from './pages/PlaceholderPage';

// All domain route paths that are not yet implemented (501 on the backend).
// Each renders PlaceholderPage until its real implementation replaces it.
const PLACEHOLDER_ROUTES = [
  '/readers',
  '/holdings',
  '/circulation',
  '/stocktake',
  '/programs',
  '/enrollments',
  '/moderation',
  '/content',
  '/feedback',
  '/appeals',
  '/reports',
  '/imports',
  '/users',
];

export default function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <Routes>
          {/* Public routes */}
          <Route path="/login" element={<LoginPage />} />
          <Route path="/unauthorized" element={<UnauthorizedPage />} />

          {/* Protected routes — wrapped by AppShell (sidebar + topbar layout) */}
          <Route
            element={
              <ProtectedRoute>
                <AppShell />
              </ProtectedRoute>
            }
          >
            {/* Root redirect */}
            <Route index element={<Navigate to="/dashboard" replace />} />

            {/* Dashboard */}
            <Route path="/dashboard" element={<DashboardPage />} />

            {/* Domain placeholders — replaced by real pages in later prompts */}
            {PLACEHOLDER_ROUTES.map((path) => (
              <Route key={path} path={`${path}/*`} element={<PlaceholderPage />} />
            ))}
          </Route>

          {/* 404 catch-all */}
          <Route path="*" element={<NotFoundPage />} />
        </Routes>
      </BrowserRouter>
    </AuthProvider>
  );
}
"}

