1	// AuthContext provides authentication state and operations throughout the app.
2	// Session state is verified against the server on initial load (GET /auth/me).
3	// Any 401 response clears local auth state and triggers a redirect to login.
4	
5	import React, { createContext, useCallback, useContext, useEffect, useState } from 'react';
6	import { apiClient } from '../api/client';
7	
8	// ── Types ─────────────────────────────────────────────────────────────────────
9	
10	export interface AuthUserCore {
11	  id: string;
12	  username: string;
13	  email: string;
14	  is_active: boolean;
15	  failed_attempts: number;
16	  locked_until?: string;
17	  last_login_at?: string;
18	  created_at: string;
19	  updated_at: string;
20	}
21	
22	// AuthUser matches the server's UserWithRoles JSON shape after json tags were added.
23	export interface AuthUser {
24	  user: AuthUserCore;
25	  roles: string[];
26	  permissions: string[];
27	}
28	
29	export interface LoginRequest {
30	  username: string;
31	  password: string;
32	  captcha_key?: string;
33	  captcha_answer?: string;
34	}
35	
36	// CaptchaChallenge is returned when the server requires CAPTCHA before next login.
37	export interface CaptchaChallenge {
38	  key: string;
39	  question: string;
40	}
41	
42	// AccountLocked is returned after 5 failed login attempts.
43	export interface AccountLocked {
44	  seconds_remaining: number;
45	}
46	
47	type AuthStatus = 'loading' | 'unauthenticated' | 'authenticated';
48	
49	export interface AuthState {
50	  status: AuthStatus;
51	  user: AuthUser | null;
52	}
53	
54	interface AuthContextValue {
55	  auth: AuthState;
56	  login: (req: LoginRequest) => Promise<void>;
57	  logout: () => Promise<void>;
58	  hasPermission: (perm: string) => boolean;
59	  hasRole: (role: string) => boolean;
60	  getPrimaryRole: () => string;
61	}
62	
63	// ── Context ───────────────────────────────────────────────────────────────────
64	
65	const AuthContext = createContext<AuthContextValue | null>(null);
66	
67	export function AuthProvider({ children }: { children: React.ReactNode }) {
68	  const [auth, setAuth] = useState<AuthState>({ status: 'loading', user: null });
69	
70	  // On mount: verify session by calling GET /auth/me.
71	  // The server validates the httpOnly session cookie and returns the current user.
72	  // This is the authoritative session check — no client-side token storage needed.
73	  useEffect(() => {
74	    apiClient
75	      .get<AuthUser>('/auth/me')
76	      .then((user) => setAuth({ status: 'authenticated', user }))
77	      .catch(() => setAuth({ status: 'unauthenticated', user: null }));
78	  }, []);
79	
80	  const login = useCallback(async (req: LoginRequest) => {
81	    // POST /auth/login returns { user: AuthUser, captcha_required: bool } on success.
82	    // The server sets the session cookie automatically.
83	    const res = await apiClient.post<{ user: AuthUser; captcha_required: boolean }>(
84	      '/auth/login',
85	      req,
86	    );
87	    setAuth({ status: 'authenticated', user: res.user });
88	  }, []);
89	
90	  const logout = useCallback(async () => {
91	    try {
92	      // POST /auth/logout invalidates the server session.
93	      await apiClient.post<void>('/auth/logout');
94	    } catch {
95	      // Clear local state regardless of server response.
96	    }
97	    setAuth({ status: 'unauthenticated', user: null });
98	  }, []);
99	
100	  const hasPermission = useCallback(
101	    (perm: string) => auth.user?.permissions.includes(perm) ?? false,
102	    [auth.user],
103	  );
104	
105	  const hasRole = useCallback(
106	    (role: string) => auth.user?.roles.includes(role) ?? false,
107	    [auth.user],
108	  );
109	
110	  const getPrimaryRole = useCallback((): string => {
111	    if (!auth.user) return 'unknown';
112	    const { roles } = auth.user;
113	    if (roles.includes('administrator')) return 'administrator';
114	    if (roles.includes('content_moderator')) return 'content_moderator';
115	    if (roles.includes('operations_staff')) return 'operations_staff';
116	    return roles[0] ?? 'unknown';
117	  }, [auth.user]);
118	
119	  return (
120	    <AuthContext.Provider value={{ auth, login, logout, hasPermission, hasRole, getPrimaryRole }}>
121	      {children}
122	    </AuthContext.Provider>
123	  );
124	}
125	
126	export function useAuth(): AuthContextValue {
127	  const ctx = useContext(AuthContext);
128	  if (!ctx) throw new Error('useAuth must be used inside AuthProvider');
129	  return ctx;
130	}
