//
// Responsibilities:
//   - Role-filtered sidebar navigation (users only see allowed routes)
//   - Branch scope display (administrators see "All branches"; others see their scope)
//   - Session inactivity tracking with warning banner and auto-logout
//   - Logout button wired to AuthContext

import { NavLink, Outlet, useNavigate } from 'react-router-dom';
import { useAuth } from '../auth/AuthContext';
import { useSessionTimeout } from '../hooks/useSessionTimeout';
import SessionTimeoutBanner from './SessionTimeoutBanner';

// ── Styles ────────────────────────────────────────────────────────────────────

const S = {
  shell: {
    display: 'flex',
    height: '100vh',
    overflow: 'hidden',
    fontFamily: 'system-ui, -apple-system, sans-serif',
    fontSize: '0.875rem',
    color: '#1a1a2e',
    background: '#f3f4f6',
  } as React.CSSProperties,

  sidebar: {
    width: '220px',
    flexShrink: 0,
    background: '#1e2235',
    color: '#c8d0e0',
    display: 'flex',
    flexDirection: 'column' as const,
    overflow: 'hidden',
  },

  sidebarHeader: {
    padding: '1rem 1rem 0.75rem',
    borderBottom: '1px solid #2a3050',
  } as React.CSSProperties,

  sidebarTitle: {
    fontSize: '0.8125rem',
    fontWeight: 700,
    color: '#e2e8f0',
    letterSpacing: '0.02em',
    lineHeight: 1.3,
  } as React.CSSProperties,

  sidebarNav: {
    flex: 1,
    overflowY: 'auto' as const,
    padding: '0.5rem 0',
  },

  navSection: {
    padding: '0.625rem 1rem 0.25rem',
    fontSize: '0.6875rem',
    fontWeight: 600,
    textTransform: 'uppercase' as const,
    letterSpacing: '0.08em',
    color: '#4a5568',
  } as React.CSSProperties,

  sidebarFooter: {
    borderTop: '1px solid #2a3050',
    padding: '0.75rem 1rem',
  } as React.CSSProperties,

  userBlock: {
    marginBottom: '0.625rem',
  } as React.CSSProperties,

  userName: {
    fontSize: '0.8125rem',
    fontWeight: 600,
    color: '#e2e8f0',
    display: 'block',
    overflow: 'hidden',
    textOverflow: 'ellipsis',
    whiteSpace: 'nowrap' as const,
  } as React.CSSProperties,

  userMeta: {
